script:
answer = true;
var email = current.email.getRefRecord();
if(email.isValidRecord()) { // << only perform operations on it if it's a valid record
   answer = email.canDelete();
}

if ((current.metric_category.metric_type+"") != "" && (current.metric_category.metric_type.survey_owners+"").indexOf(gs.getUserID()) !== -1)
	answer = true;
else 
	answer = false;

//this is a function mimicking the backend logic applied to determine visibility of a table in the Table dropdown
function isPermitted(table) { 
	if (!table.startsWith("sys")) 
		return true; 

	var permitted_sys_tables = GlideProperties.get("glide.ui.permitted_tables"); 
	if (!permitted_sys_tables) 
		return false; 

	var permitted_tables = permitted_sys_tables.split(","); 
	for (var i = 0; i < permitted_tables.length; i++) { 
		if (permitted_tables[i] == table) 
			return true; 

	} 
	return false; 
} 

if(current.table != '') { 
    var tableDescriptor = GlideTableDescriptor.get(current.table); 
    answer = tableDescriptor && tableDescriptor.isValid() && tableDescriptor.canRead() && isPermitted(current.table) && new GlideReportChoiceList().hasReportRights(current.table); 
} else 
    answer = true;

function checkAccess() {
	// Check if parent has run out on us
	var localParent = null;
	try {
		localParent = parent;
	}
	catch (e) {
		localParent = null;
	}

	// If it's not being created from a related list on sttrm_state_transition return false
	if (localParent && localParent.getTableName() !== "sttrm_state_transition")
		return false;

	//Check that we either have a local parent (new/edit from list) or a state (on insert of record)
	if (!localParent && current.sttrm_state_transition.nil())
		return false;

	// Populate the model to check, confirming correct structure
	var model = null;
	if (localParent && localParent.from_state && localParent.from_state.sttrm_model) {
		model = localParent.from_state.sttrm_model.getRefRecord();
	}
	else if (current.sttrm_state_transition && current.sttrm_state_transition.from_state && current.sttrm_state_transition.from_state.sttrm_model) {
		model = current.sttrm_state_transition.from_state.sttrm_model.getRefRecord();
	}

	// If there's no model, no access
	if (!model)
		return false;

	return model.canWrite();
}

checkAccess();

var gr = new GlideRecord('par_dashboard_canvas');
gr.get(current.getValue('canvas'));
answer = gr.isValid() && gr.canWrite();

var gr = new GlideRecord('cmdb_contract_product_model');
gr.get("name", "subscription");
answer = gs.hasRole('contract_manager') || (current.contract_model == gr.sys_id);

answer = getConfigCreateAnswer();

function getConfigCreateAnswer() {
	var gr = new GlideRecord("wm_map_filters_config");
	gr.addQuery("user", gs.getUserID());
	gr.query();
	if (gr.next()) {
	   return false;
	} 
	return true;
}

var docTaskGr = new GlideRecord("sn_doc_task");
docTaskGr.addQuery("assigned_to", gs.getUserID());
docTaskGr.setLimit(1);
docTaskGr.query();
answer = docTaskGr.hasNext();

answer = getAttributeCreateAnswer();

function getAttributeCreateAnswer() {
    var gr = new GlideRecord('sys_attachment');
    if (!gr.get(current.sys_attachment))
        return false;

	if(gs.hasRole('maint')) return true;
    return current.sys_attachment.getRefRecord().canCreate();
}

// 	Check write access for HR response template

var table = current.table.toString();
var isHRTable = table.startsWith('sn_hr');

answer = isHRTable? new sn_templated_snip.NoteTemplateCheck().canAccessHRResponseTemplate(table, 'write') : true;

if (gs.hasRole('nlu_admin')) {
    answer = true;
} else if (gs.hasRole('nlu_editor') && NLUBatchTestSet.canUserCreateUpdateRecord) {
    answer = NLUBatchTestSet.canUserCreateUpdateRecord(current.test_set, gs.getUserID());
} else {
    answer = false;
}
